// Collect into a single batch + render Slack copy.
const rows = $items().map(i => i.json);
const correlationId = rows[0]?.correlationId || `fb-daily-${Date.now()}`;
const lines = rows.map(r => `• *${r.campaignName}* — ${r.action.toUpperCase()}${r.action==='scale_up'?` (+${Math.round((r.delta||0.2)*100)}%)`:''} — ${r.reason}`);
const slackText = `*FB Daily Ad Recommendations* (correlation: \`${correlationId}\`)
Yesterday: ${rows[0]?.yesterday}
${rows.length} action(s):
${lines.join('
')}

Approve → click the resume link below.
Reject → click the reject link below.`;
return [{ json: { correlationId, yesterday: rows[0]?.yesterday, batch: rows, slackText } }];
